import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";
import pattern from "../slike/pattern4.jpg";
import { useEffect,useState } from "react";

export function PravljenjeRezervacije(){

        const[rezervacije,setRezervacije]=useState([]);
      useEffect(() => {

        fetch("http://localhost:8080/reservations/getReservationStatus/PENDING")
             .then((res) => res.json())
      .then((data) => {
        if (data && data.data && data.data.values) {
          setRezervacije(data.data.values);
        }
      })
      .catch((err) => console.error("Greška pri učitavanju rezervacija:", err));

      console.log(rezervacije);
}, []);

function odobriRezervaciju(rezervacija){
    setRezervacije(prev =>
        prev.map(r => r.idRezervacija === rezervacija.idRezervacija 
            ? {...r, status: "CONFIRMED"} 
            : r
        )
    );
}

function odbiRezervaciju(rezervacija){
    setRezervacije(prev =>
        prev.map(r => r.idRezervacija === rezervacija.idRezervacija 
            ? {...r, status: "CANCELLED"} 
            : r
        )
    );
}
    

    return(<>
   <div
        style={{
          minHeight: "100vh",
          display: "flex",
          flexDirection: "column",
          justifyContent: "space-between",
        }}
      >
        <NavBarRecepcionar />
  
        <div
          style={{
            backgroundImage: `url(${pattern})`,
            backgroundSize: "cover",
            backgroundPosition: "center",
            minHeight: "100vh",
            padding: "40px",
          }}
        >
<div style={{
    display: "flex",
    flexWrap: "wrap", 
    gap: "10px",      
    justifyContent: "flex-start",
    padding: "20px"
}}>            {
                rezervacije.map((rezervacija) => {
    return (
       <div
        style={{
            background: "#af65c5",
            margin: "10px 0",
            padding: "10px",
            borderRadius: "8px",
            color: "white",
            width:"20%",
            height:"20%"
        }}
        key={rezervacija.idRezervacija}
    >
        <p>Pocetak: {rezervacija.datumPrijave}</p>
        <p>Kraj: {rezervacija.datumOdjave}</p>
        <p>Broj osoba: {rezervacija.brojOsoba}</p>
        <p>Iznos: {rezervacija.ukupanIznos} din</p>
        <p>Broj sobe: {rezervacija.soba.brojSobe}</p>
        <p>Sprat: {rezervacija.soba.sprat}</p>
        <p>Tip: {rezervacija.soba.tipSobe.naziv}</p>
        <p>Cena po noći: {rezervacija.soba.tipSobe.cenaPoNoci} din</p>
        <p>{rezervacija.soba.tipSobe.opis}</p>
        <p>Zahtev podneo: {rezervacija.gost.email}</p>
        <div style={{display:"flex",justifyContent:"center",margin:"auto"}}>
            <span className="formaSpan" style={{width:"30px"}} onClick={()=>odobriRezervaciju(rezervacija)} ><p>Odobri rezervaciju</p></span>
            <span className="formaSpan" onClick={()=>odbiRezervaciju(rezervacija)}><p>Odbi rezervaciju</p></span>
        </div>
    </div>
    );
})

            }
        </div>
        </div>
        
     

        </div>

    <Footer />
    
    </>)
}
